// Step 1: Raw output from LLM
const rawString = $input.first().json.output;

// Step 2: Clean unwanted formatting
let cleanedString = rawString.replace(/```json/g, '').replace(/```/g, '').trim();
cleanedString = cleanedString.replace(/\\n/g, '').replace(/\\"/g, '"').trim();

// Step 3: Parse the whole JSON object
let parsed;
try {
  parsed = JSON.parse(cleanedString);
} catch (error) {
  throw new Error("JSON parsing failed: " + error.message + " | Cleaned string was: " + cleanedString);
}

// Step 4: Check if 'story' exists and is array
if (!Array.isArray(parsed.story)) {
  throw new Error("Expected 'story' to be an array but got: " + typeof parsed.story);
}

// Step 5: Return each scene as individual output
return parsed.story.map(scene => ({ json: scene }));

