parameters.jsCode:
const urls = $json.url;
const durations = $json.Duration;

let clips = [];
let start = 0;

for (let i = 0; i < urls.length; i++) {
  const transition = {};
  if (i === 0) {
    transition.out = "fade";
  } else if (i === urls.length - 1) {
    transition.in = "fade";
  } else {
    transition.in = "fade";
    transition.out = "fade";
  }

  clips.push({
    asset: {
      type: "video",
      src: urls[i]
    },
    start: start,
    length: Number(durations[i]),
    transition
  });

  start += Number(durations[i]);
}

return [
  {
    json: {
      output: {
        format: "mp4",
        resolution: "1080",
        aspectRatio: $('Edit Fields1').first().json.aspectRatio,
        fps: 25
      },
      timeline: {
        tracks: [
          {
            clips
          }
        ]
      }
    }
  }
];

